import React, { createContext, useState, useEffect, useContext } from 'react';
import { View, ActivityIndicator, StyleSheet, Text, TextInput, Button, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

// --- 1. AuthContext.js ---
const AuthContext = createContext();

const AuthProvider = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const token = await AsyncStorage.getItem('userToken');
        const user = await AsyncStorage.getItem('userData');
        if (token && user) {
          setUserToken(token);
          setUserData(JSON.parse(user));
        }
      } catch (e) {
        console.error('Failed to load auth data from storage', e);
      } finally {
        setIsLoading(false);
      }
    };

    loadStoredData();
  }, []);

  const authContext = React.useMemo(
    () => ({
      signIn: async (email, password) => {
        setIsLoading(true);
        // Simulate API call
        return new Promise((resolve, reject) => {
          setTimeout(async () => {
            if (email === 'test@example.com' && password === 'password') {
              const token = 'dummy-auth-token-123';
              const user = { id: '1', email: email, name: 'Test User' };
              await AsyncStorage.setItem('userToken', token);
              await AsyncStorage.setItem('userData', JSON.stringify(user));
              setUserToken(token);
              setUserData(user);
              setIsLoading(false);
              resolve({ token, user });
            } else {
              setIsLoading(false);
              reject(new Error('Invalid credentials'));
            }
          }, 1500);
        });
      },
      signUp: async (email, password) => {
        setIsLoading(true);
        // Simulate API call for signup
        return new Promise((resolve, reject) => {
          setTimeout(async () => {
            // In a real app, you'd send this to your backend
            // and receive a token and user data.
            const token = `dummy-auth-token-${Math.random().toString(36).substring(7)}`;
            const user = { id: Math.random().toString(36).substring(7), email: email, name: 'New User' };
            await AsyncStorage.setItem('userToken', token);
            await AsyncStorage.setItem('userData', JSON.stringify(user));
            setUserToken(token);
            setUserData(user);
            setIsLoading(false);
            resolve({ token, user });
          }, 1500);
        });
      },
      signOut: async () => {
        setIsLoading(true);
        try {
          await AsyncStorage.removeItem('userToken');
          await AsyncStorage.removeItem('userData');
          setUserToken(null);
          setUserData(null);
        } catch (e) {
          console.error('Failed to remove auth data from storage', e);
        } finally {
          setIsLoading(false);
        }
      },
      userToken,
      userData,
      isLoading,
    }),
    [userToken, userData, isLoading]
  );

  return (
    <AuthContext.Provider value={authContext}>
      {children}
    </AuthContext.Provider>
  );
};

// --- 2. Screens ---

// Loading Screen
const LoadingScreen = () => (
  <View style={styles.container}>
    <ActivityIndicator size="large" />
    <Text>Loading...</Text>
  </View>
);

// Login Screen
const LoginScreen = ({ navigation }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { signIn } = useContext(AuthContext);

  const handleLogin = async () => {
    try {
      await signIn(email, password);
    } catch (error) {
      Alert.alert('Login Failed', error.message);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>
      <TextInput
        style={styles.input}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        keyboardType="email-address"
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />
      <Button title="Login" onPress={handleLogin} />
      <Button title="Don't have an account? Sign Up" onPress={() => navigation.navigate('SignUp')} />
    </View>
  );
};

// Signup Screen
const SignUpScreen = ({ navigation }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { signUp } = useContext(AuthContext);

  const handleSignUp = async () => {
    try {
      await signUp(email, password);
    } catch (error) {
      Alert.alert('Signup Failed', error.message);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Sign Up</Text>
      <TextInput
        style={styles.input}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        keyboardType="email-address"
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />
      <Button title="Sign Up" onPress={handleSignUp} />
      <Button title="Already have an account? Login" onPress={() => navigation.navigate('Login')} />
    </View>
  );
};

// Home Screen (Authenticated)
const HomeScreen = () => {
  const { signOut, userData } = useContext(AuthContext);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome!</Text>
      {userData && (
        <View style={styles.userDataContainer}>
          <Text>User ID: {userData.id}</Text>
          <Text>Email: {userData.email}</Text>
          <Text>Name: {userData.name}</Text>
        </View>
      )}
      <Button title="Logout" onPress={signOut} />
    </View>
  );
};

// --- 3. Navigation ---

const AuthStack = createNativeStackNavigator();
const AppStack = createNativeStackNavigator();

const AuthNavigator = () => (
  <AuthStack.Navigator screenOptions={{ headerShown: false }}>
    <AuthStack.Screen name="Login" component={LoginScreen} />
    <AuthStack.Screen name="SignUp" component={SignUpScreen} />
  </AuthStack.Navigator>
);

const AppNavigator = () => (
  <AppStack.Navigator>
    <AppStack.Screen name="Home" component={HomeScreen} options={{ title: 'Home' }} />
  </AppStack.Navigator>
);

// Root Navigator
const RootNavigator = () => {
  const { userToken, isLoading } = useContext(AuthContext);

  if (isLoading) {
    return <LoadingScreen />;
  }

  return (
    <NavigationContainer>
      {userToken ? <AppNavigator /> : <AuthNavigator />}
    </NavigationContainer>
  );
};

// --- 4. App.js ---
const App = () => {
  return (
    <AuthProvider>
      <RootNavigator />
    </AuthProvider>
  );
};

